--------------------------------------------------------
-- Sychronize temp table and real table by            --
-- inserting, deleting, and updating as necessary     --
--------------------------------------------------------

INSERT INTO PSP_ROLE_SUB_STATUS
   (ROLE_SUB_STATUS_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, ALLOWED_CHANGE_TYPE,SERVICE_SUB_STATUS_FK,AUTH_ROLE_FK)
SELECT
    ROLE_SUB_STATUS_SEQ, VERSION, CREATED_DATE, MODIFIED_DATE, ALLOWED_CHANGE_TYPE,SERVICE_SUB_STATUS_FK,AUTH_ROLE_FK
FROM
   TEMP_PSP_ROLE_SUB_STATUS tt
WHERE
   tt.ROLE_SUB_STATUS_SEQ NOT IN (SELECT ROLE_SUB_STATUS_SEQ FROM PSP_ROLE_SUB_STATUS)

;

DELETE FROM PSP_ROLE_SUB_STATUS
WHERE ROLE_SUB_STATUS_SEQ NOT IN (SELECT ROLE_SUB_STATUS_SEQ FROM TEMP_PSP_ROLE_SUB_STATUS)

;

UPDATE PSP_ROLE_SUB_STATUS rt
SET (VERSION, CREATED_DATE, MODIFIED_DATE, ALLOWED_CHANGE_TYPE, SERVICE_SUB_STATUS_FK, AUTH_ROLE_FK) =
(SELECT tt.VERSION, tt.CREATED_DATE, tt.MODIFIED_DATE, tt.ALLOWED_CHANGE_TYPE,tt.SERVICE_SUB_STATUS_FK,tt.AUTH_ROLE_FK
 FROM TEMP_PSP_ROLE_SUB_STATUS tt WHERE tt.ROLE_SUB_STATUS_SEQ = rt.ROLE_SUB_STATUS_SEQ)
;

--------------------------------------------------------
-- Drop temp table                                  --
--------------------------------------------------------
DROP TABLE TEMP_PSP_ROLE_SUB_STATUS

;
COMMIT
